  1→// Power-up system - extracted from game.js
  2→// All functions take `game` as first parameter
  3→
  4→import { TILE_TYPE, FEATURE_KEYS } from "./config.js";
  5→import {
  6→    isBlockedWithLife,
  7→    isRectangularBlocked,
  8→    isBlockedWithMergeCount,
  9→    isBlocked,
 10→    isBlockedMovable,
 11→    isNormal,
 12→    createTile,
 13→    createCursedTile,
 14→    isCursed,
 15→    getDisplayValue,
 16→    getFontSize,
 17→} from "./tile-helpers.js";
 18→import { savePowerUpCounts, isFeatureUnlocked } from "./storage.js";
 19→import { track } from "./tracker.js";
 20→import {
 21→    isTutorialActive,
 22→    isTutorialPowerUpStep,
 23→    isValidTutorialPowerUp,
 24→    updateTutorialUI,
 25→} from "./tutorial.js";
 26→
 27→export function setupPowerUps(game) {
 28→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
 29→
 30→    powerUpButtons.forEach((button) => {
 31→        button.addEventListener("click", () => {
 32→            if (!game.gameActive) return;
 33→
 34→            const powerUpType = button.dataset.powerup;
 35→
 36→            if (!isPowerUpButtonVisible(game, powerUpType)) {
 37→                return;
 38→            }
 39→
 40→            if (getTotalPowerUpCount(game, powerUpType) <= 0) {
 41→                openPowerupShop(game);
 42→                return;
 43→            }
 44→
 45→            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 46→                if (!isValidTutorialPowerUp(game, powerUpType)) {
 47→                    return;
 48→                }
 49→            }
 50→
 51→            if (game.activePowerUp === powerUpType) {
 52→                deactivatePowerUp(game);
 53→            } else {
 54→                activatePowerUp(game, powerUpType);
 55→            }
 56→        });
 57→    });
 58→}
 59→
 60→export function activatePowerUp(game, type) {
 61→    if (isTutorialActive(game) && !isTutorialPowerUpStep(game)) {
 62→        return;
 63→    }
 64→
 65→    deactivatePowerUp(game);
 66→    game.activePowerUp = type;
 67→    game.powerUpSwapTiles = [];
 68→
 69→    const button = document.querySelector(`[data-powerup="${type}"]`);
 70→    if (button) {
 71→        button.classList.add("active");
 72→    }
 73→
 74→    if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 75→        updateTutorialUI(game);
 76→    }
 77→}
 78→
 79→export function deactivatePowerUp(game) {
 80→    if (game.activePowerUp) {
 81→        const button = document.querySelector(`[data-powerup="${game.activePowerUp}"]`);
 82→        if (button) {
 83→            button.classList.remove("active");
 84→        }
 85→    }
 86→
 87→    game.activePowerUp = null;
 88→    game.powerUpSwapTiles = [];
 89→}
 90→
 91→export function isPowerUpButtonVisible(game, powerUpType) {
 92→    const idx = game.selectedPowerUps.indexOf(powerUpType);
 93→    if (idx === -1) return false;
 94→
 95→    const unlockKeys = [FEATURE_KEYS.POWER_UP_1, FEATURE_KEYS.POWER_UP_2, FEATURE_KEYS.POWER_UP_3];
 96→    let unlockedSlots = 0;
 97→    for (const key of unlockKeys) {
 98→        if (isFeatureUnlocked(key)) unlockedSlots++;
 99→        else break;
100→    }
101→
102→    return idx < unlockedSlots;
103→}
104→
105→export function getVisiblePowerUpTypes(game) {
106→    return game.selectedPowerUps.filter((t) => isPowerUpButtonVisible(game, t));
107→}
108→
109→export function grantPowerUp(game, powerUpType) {
110→    game.powerUpCounts[powerUpType].transient++;
111→    updatePowerUpButtons(game);
112→}
113→
114→export function getTotalPowerUpCount(game, type) {
115→    const counts = game.powerUpCounts[type];
116→    const persistent = game.persistentPowerUpsEnabled ? counts.persistent : 0;
117→    return persistent + counts.transient;
118→}
119→
120→export function consumePowerUp(game, type) {
121→    game.powerUpUsedCounts[type]++;
122→
123→    const counts = game.powerUpCounts[type];
124→    if (counts.transient > 0) {
125→        counts.transient--;
126→    } else if (game.persistentPowerUpsEnabled && counts.persistent > 0) {
127→        counts.persistent--;
128→        savePowerUpCounts({
129→            hammer: game.powerUpCounts.hammer.persistent,
130→            halve: game.powerUpCounts.halve.persistent,
131→            swap: game.powerUpCounts.swap.persistent,
132→            teleport: game.powerUpCounts.teleport.persistent,
133→            wildcard: game.powerUpCounts.wildcard.persistent,
134→        });
135→    }
136→}
137→
138→export function grantFormationPowerUp(game, formationType) {
139→    if (!game.formationPowerUpRewards) return;
140→
141→    const formationToPowerUp = {
142→        "L-formation": "hammer",
143→        "T-formation": "halve",
144→        line_5_horizontal: "swap",
145→        line_5_vertical: "swap",
146→    };
147→
148→    const powerUpType = formationToPowerUp[formationType];
149→    if (!powerUpType) return;
150→
151→    if (!isPowerUpButtonVisible(game, powerUpType)) return;
152→
153→    grantPowerUp(game, powerUpType);
154→    showPowerUpRewardAnimation(game, powerUpType);
155→}
156→
157→export function showPowerUpRewardAnimation(game, powerUpType) {
158→    const motivationalWords = ["Great!", "Awesome!", "Wow!", "Amazing!", "Nice!", "Super!"];
159→    const randomWord = motivationalWords[Math.floor(Math.random() * motivationalWords.length)];
160→
161→    const powerUpIcons = {
162→        hammer: "🔨",
163→        halve: "✂️",
164→        swap: "🔄",
165→        teleport: "🚀",
166→        wildcard: "✨",
167→    };
168→    const icon = powerUpIcons[powerUpType];
169→
170→    const container = document.createElement("div");
171→    container.className = "formation-powerup-animation";
172→
173→    const headline = document.createElement("stroked-text");
174→    headline.className = "formation-powerup-headline";
175→    headline.setAttribute("text", randomWord);
176→    headline.setAttribute("font-size", "48");
177→    headline.setAttribute("stroke-width", "12");
178→    headline.setAttribute("fill", "#FFD700");
179→    headline.setAttribute("stroke", "#333");
180→
181→    const subtitleContainer = document.createElement("div");
182→    subtitleContainer.className = "formation-powerup-subtitle";
183→
184→    const plusOneText = document.createElement("stroked-text");
185→    plusOneText.setAttribute("text", "+1");
186→    plusOneText.setAttribute("font-size", "36");
187→    plusOneText.setAttribute("stroke-width", "10");
188→    plusOneText.setAttribute("fill", "#FFFFFF");
189→    plusOneText.setAttribute("stroke", "#333");
190→
191→    const iconText = document.createElement("stroked-text");
192→    iconText.setAttribute("text", icon);
193→    iconText.setAttribute("font-size", "36");
194→    iconText.setAttribute("stroke-width", "6");
195→
196→    subtitleContainer.appendChild(plusOneText);
197→    subtitleContainer.appendChild(iconText);
198→
199→    container.appendChild(headline);
200→    container.appendChild(subtitleContainer);
201→
202→    const gameContainer = document.getElementById("game-container");
203→    if (gameContainer) {
204→        gameContainer.appendChild(container);
205→        setTimeout(() => {
206→            container.remove();
207→        }, 2000);
208→    }
209→}
210→
211→export function showPowerUps(game) {
212→    const powerUpsContainer = document.querySelector(".power-ups");
213→    if (powerUpsContainer) {
214→        powerUpsContainer.style.visibility = "";
215→    }
216→    const allButtons = document.querySelectorAll(".power-up-btn.game");
217→    allButtons.forEach((btn) => {
218→        btn.style.display = game.selectedPowerUps.includes(btn.dataset.powerup) ? "" : "none";
219→    });
220→}
221→
222→export function hidePowerUps(game) {
223→    const powerUpsContainer = document.querySelector(".power-ups");
224→    if (powerUpsContainer) {
225→        powerUpsContainer.style.visibility = "hidden";
226→    }
227→}
228→
229→export function updatePowerUpButtons(game) {
230→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
231→
232→    powerUpButtons.forEach((button) => {
233→        const powerUpType = button.dataset.powerup;
234→
235→        if (!isPowerUpButtonVisible(game, powerUpType)) {
236→            button.classList.add("locked");
237→            button.disabled = true;
238→            button.title = "Unlock by progressing through levels";
239→            const existingIndicator = button.querySelector(".use-indicator");
240→            if (existingIndicator) {
241→                existingIndicator.remove();
242→            }
243→            return;
244→        }
245→
246→        button.classList.remove("locked");
247→        button.disabled = false;
248→
249→        const counts = game.powerUpCounts[powerUpType];
250→        const persistent = game.persistentPowerUpsEnabled ? counts.persistent : 0;
251→        const transient = counts.transient;
252→        const total = persistent + transient;
253→
254→        const existingIndicator = button.querySelector(".use-indicator");
255→        if (existingIndicator) {
256→            existingIndicator.remove();
257→        }
258→
259→        if (total <= 0) {
260→            button.classList.add("can-purchase");
261→            button.title = `${button.title.split(" - ")[0]} - Click to buy more`;
262→        } else {
263→            button.classList.remove("can-purchase");
264→            const indicator = document.createElement("div");
265→            indicator.className = "use-indicator";
266→
267→            const strokedText = document.createElement("stroked-text");
268→            strokedText.setAttribute("text", total);
269→            strokedText.setAttribute("font-size", "26");
270→            strokedText.setAttribute("width", "40");
271→            strokedText.setAttribute("height", "40");
272→            strokedText.setAttribute("svg-style", "width: 100%; height: 100%;");
273→
274→            if (transient > 0) {
275→                indicator.classList.add("transient-count");
276→            }
277→
278→            indicator.appendChild(strokedText);
279→            button.appendChild(indicator);
280→
281→            button.classList.remove("disabled");
282→            const baseTitle = button.title.split(" - ")[0];
283→            button.title = `${baseTitle} - ${total} uses left`;
284→        }
285→    });
286→
287→    }
288→}
