290→export function handlePowerUpAction(game, row, col, element) {
291→    const tile = game.board[row][col];
292→
293→    switch (game.activePowerUp) {
294→        case "hammer":
295→            if (!tile) return;
296→            const allowedTypes = [
297→                TILE_TYPE.NORMAL,
298→                TILE_TYPE.BLOCKED_MOVABLE,
299→                TILE_TYPE.BLOCKED,
300→                TILE_TYPE.BLOCKED_WITH_LIFE,
301→            ];
302→            if (!allowedTypes.includes(tile.type)) return;
303→            usePowerUpHammer(game, row, col, element);
304→            break;
305→        case "halve":
306→            usePowerUpHalve(game, row, col, element);
307→            break;
308→        case "swap":
309→        case "teleport":
310→            return false;
311→        case "wildcard":
312→            usePowerUpWildcard(game, row, col, element);
313→            break;
314→    }
315→}
316→
317→export function usePowerUpHammer(game, row, col, element) {
318→    const tile = game.board[row][col];
319→
320→    game.resetHintTimer();
321→
322→    consumePowerUp(game, "hammer");
323→    updatePowerUpButtons(game);
324→
325→    track("power_up_used", {
326→        level: game.currentLevel,
327→        power_up_type: "hammer",
328→        remaining_moves: game.maxMoves - game.movesUsed,
329→        uses_remaining: getTotalPowerUpCount(game, "hammer"),
330→    });
331→
332→    game.animating = true;
333→
334→    if (isBlockedWithLife(tile)) {
335→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
336→        element.style.opacity = "0";
337→        element.style.transform = "scale(0)";
338→
339→        setTimeout(() => {
340→            if (isRectangularBlocked(tile)) {
341→                for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
342→                    for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
343→                        if (r >= 0 && r < game.boardHeight && c >= 0 && c < game.boardWidth) {
344→                            game.board[r][c] = null;
345→                        }
346→                    }
347→                }
348→            } else {
349→                game.board[row][col] = null;
350→            }
351→
352→            game.updateBlockedTileGoals();
353→            game.dropGems();
354→            deactivatePowerUp(game);
355→        }, 300);
356→    } else if (isBlockedWithMergeCount(tile)) {
357→        let cellToClear = null;
358→        for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
359→            for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
360→                const cellKey = `${r}_${c}`;
361→                if (tile.cellMergeCounts[cellKey] > 0) {
362→                    cellToClear = { row: r, col: c, cellKey: cellKey };
363→                    break;
364→                }
365→            }
366→            if (cellToClear) break;
367→        }
368→
369→        if (cellToClear) {
370→            tile.cellMergeCounts[cellToClear.cellKey]--;
371→
372→            const allCleared = Object.values(tile.cellMergeCounts).every((count) => count === 0);
373→
374→            if (allCleared) {
375→                element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
376→                element.style.opacity = "0";
377→                element.style.transform = "scale(0)";
378→
379→                setTimeout(() => {
380→                    for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
381→                        for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
382→                            if (r >= 0 && r < game.boardHeight && c >= 0 && c < game.boardWidth) {
383→                                game.board[r][c] = null;
384→                            }
385→                        }
386→                    }
387→
388→                    game.updateBlockedTileGoals();
389→                    game.dropGems();
390→                    deactivatePowerUp(game);
391→                }, 300);
392→            } else {
393→                element.style.transition = "transform 0.2s ease";
394→                element.style.transform = "scale(1.1)";
395→
396→                setTimeout(() => {
397→                    element.style.transform = "scale(1)";
398→                    game.renderBoard();
399→                    game.animating = false;
400→                    deactivatePowerUp(game);
401→                }, 200);
402→            }
403→        } else {
404→            game.animating = false;
405→            deactivatePowerUp(game);
406→        }
407→    } else if (isBlocked(tile) || isBlockedMovable(tile)) {
408→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
409→        element.style.opacity = "0";
410→        element.style.transform = "scale(0)";
411→
412→        setTimeout(() => {
413→            if (isRectangularBlocked(tile)) {
414→                for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
415→                    for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
416→                        if (r >= 0 && r < game.boardHeight && c >= 0 && c < game.boardWidth) {
417→                            game.board[r][c] = null;
418→                        }
419→                    }
420→                }
421→            } else {
422→                game.board[row][col] = null;
423→            }
424→
425→            game.updateBlockedTileGoals();
426→            game.dropGems();
427→            deactivatePowerUp(game);
428→        }, 300);
429→    } else {
430→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
431→        element.style.opacity = "0";
432→        element.style.transform = "scale(0)";
433→
434→        setTimeout(() => {
435→            game.board[row][col] = null;
436→            game.dropGems();
437→            deactivatePowerUp(game);
438→        }, 300);
439→    }
440→}
