442→export function usePowerUpHalve(game, row, col, element) {
443→    const tile = game.board[row][col];
444→    const isCursedTile = isCursed(tile);
445→    const currentValue = tile && (tile.type === TILE_TYPE.NORMAL || isCursedTile) ? tile.value : null;
446→
447→    if (currentValue && currentValue > 1) {
448→        game.resetHintTimer();
449→
450→        consumePowerUp(game, "halve");
451→        updatePowerUpButtons(game);
452→
453→        track("power_up_used", {
454→            level: game.currentLevel,
455→            power_up_type: "halve",
456→            remaining_moves: game.maxMoves - game.movesUsed,
457→            uses_remaining: getTotalPowerUpCount(game, "halve"),
458→        });
459→
460→        game.animating = true;
461→
462→        const halvedValue = currentValue - 1;
463→
464→        if (isCursedTile) {
465→            game.board[row][col] = createCursedTile(halvedValue, tile.cursedMovesRemaining);
466→        } else {
467→            game.board[row][col] = createTile(halvedValue);
468→        }
469→
470→        game.levelGoals.forEach((goal) => {
471→            if (goal.tileValue === halvedValue) {
472→                goal.created += 1;
473→            }
474→        });
475→
476→        const displayValue = getDisplayValue(halvedValue);
477→        const fontSize = getFontSize(displayValue);
478→        element.innerHTML = `<span style="font-size: ${fontSize}cqw">${displayValue}</span>`;
479→        element.className = `gem tile-${halvedValue}`;
480→        if (isCursedTile) {
481→            element.classList.add("cursed-tile");
482→            element.dataset.cursedMoves = tile.cursedMovesRemaining;
483→        }
484→        element.dataset.row = row;
485→        element.dataset.col = col;
486→
487→        element.style.transform = "scale(1.2)";
488→        setTimeout(() => {
489→            element.style.transform = "scale(1)";
490→            game.updateGoalDisplay(false);
491→
492→            setTimeout(() => {
493→                game.animating = false;
494→                game.processMatches();
495→            }, 100);
496→        }, 200);
497→
498→        deactivatePowerUp(game);
499→    }
500→}
501→
502→export function usePowerUpWildcard(game, row, col, element) {
503→    const tile = game.board[row][col];
504→
505→    if (!tile || !isNormal(tile)) return;
506→
507→    game.resetHintTimer();
508→
509→    consumePowerUp(game, "wildcard");
510→    updatePowerUpButtons(game);
511→
512→    track("power_up_used", {
513→        level: game.currentLevel,
514→        power_up_type: "wildcard",
515→        remaining_moves: game.maxMoves - game.movesUsed,
516→        uses_remaining: getTotalPowerUpCount(game, "wildcard"),
517→    });
518→
519→    game.animating = true;
520→
521→    game.board[row][col] = {
522→        type: TILE_TYPE.JOKER,
523→        value: null,
524→        targetValue: null,
525→        specialType: null,
526→        hasBeenSwapped: false,
527→    };
528→
529→    element.style.transition = "transform 0.3s ease";
530→    element.style.transform = "scale(1.3)";
531→    setTimeout(() => {
532→        element.style.transform = "scale(1)";
533→        game.renderBoard();
534→        game.animating = false;
535→    }, 300);
536→
537→    deactivatePowerUp(game);
538→}
