540→export function setupPowerupShop(game) {
541→    const powerupShopDialog = document.getElementById("powerupShopDialog");
542→    const closePowerupShopBtn = document.getElementById("closePowerupShopBtn");
543→    const powerupBuyButtons = document.querySelectorAll(".powerup-buy-btn");
544→
545→    if (closePowerupShopBtn) {
546→        closePowerupShopBtn.addEventListener("click", () => {
547→            powerupShopDialog.classList.add("hidden");
548→        });
549→    }
550→
551→    if (powerupShopDialog) {
552→        powerupShopDialog.addEventListener("click", (e) => {
553→            if (e.target === powerupShopDialog) {
554→                powerupShopDialog.classList.add("hidden");
555→            }
556→        });
557→    }
558→
559→    powerupBuyButtons.forEach((button) => {
560→        const originalHTML = button.innerHTML;
561→        let isPurchasing = false;
562→
563→        button.addEventListener("click", (e) => {
564→            e.stopPropagation();
565→
566→            if (isPurchasing) return;
567→
568→            const shopItem = button.closest(".powerup-shop-item");
569→            const powerupType = shopItem.getAttribute("data-powerup");
570→            const cost = parseInt(shopItem.getAttribute("data-cost"));
571→
572→            if (isNaN(cost) || isNaN(game.coins)) {
573→                return;
574→            }
575→
576→            if (game.coins >= cost) {
577→                isPurchasing = true;
578→
579→                game.coins = Number(game.coins) - Number(cost);
580→                game.saveCoins();
581→
582→                if (game.persistentPowerUpsEnabled) {
583→                    game.powerUpCounts[powerupType].persistent++;
584→                    savePowerUpCounts({
585→                        hammer: game.powerUpCounts.hammer.persistent,
586→                        halve: game.powerUpCounts.halve.persistent,
587→                        swap: game.powerUpCounts.swap.persistent,
588→                        teleport: game.powerUpCounts.teleport.persistent,
589→                        wildcard: game.powerUpCounts.wildcard.persistent,
590→                    });
591→                } else {
592→                    game.powerUpCounts[powerupType].transient++;
593→                }
594→
595→                updatePowerUpButtons(game);
596→                game.updateCoinsDisplays();
597→
598→                const originalBg = button.style.background;
599→                button.textContent = "✓";
600→                button.style.background = "#8bc34a";
601→                setTimeout(() => {
602→                    button.innerHTML = originalHTML;
603→                    button.style.background = originalBg;
604→                    isPurchasing = false;
605→                }, 1500);
606→            } else {
607→                const shopDialog = document.getElementById("shopDialog");
608→                if (shopDialog) {
609→                    shopDialog.classList.remove("hidden");
610→                    game.updateCoinsDisplays();
611→                }
612→            }
613→        });
614→    });
615→}
616→
617→export function openPowerupShop(game) {
618→    const powerupShopDialog = document.getElementById("powerupShopDialog");
619→    if (powerupShopDialog) {
620→        game.updateCoinsDisplays();
621→
622→        const shopItems = powerupShopDialog.querySelectorAll(".powerup-shop-item");
623→        shopItems.forEach((item) => {
624→            const powerupType = item.dataset.powerup;
625→            item.style.display = isPowerUpButtonVisible(game, powerupType) ? "" : "none";
626→        });
627→
628→        powerupShopDialog.classList.remove("hidden");
629→    }
630→}
