  2→
  3→export function loadSpecialTileConfig() {
  4→    const saved = localStorage.getItem("match2048_specialTileConfig_v2");
  5→    if (saved) {
  6→        return JSON.parse(saved);
  7→    }
  8→    // Default configuration
  9→    return {
 10→        line_4: "freeswap_horizontal",
 11→        block_4: "freeswap_horizontal",
 12→        line_5: "joker",
 13→        t_formation: "freeswap",
 14→        l_formation: "freeswap",
 15→    };
 16→}
 17→
 18→export function saveSpecialTileConfig(specialTileConfig) {
 19→    localStorage.setItem("match2048_specialTileConfig_v2", JSON.stringify(specialTileConfig));
 20→}
 21→
 22→export function loadCurrentLevel() {
 23→    const savedLevel = localStorage.getItem("match2048_currentLevel");
 24→    return savedLevel ? parseInt(savedLevel, 10) : 1;
 25→}
