251→    game.animating = true;
252→    element.style.transform = "scale(0.5)";
253→    element.style.opacity = "0";
254→
255→    setTimeout(() => {
256→        // Remove the tile from the board
257→        game.board[row][col] = null;
258→        game.renderBoard();
259→
260→        setTimeout(() => {
261→            // Drop tiles and process matches
262→            game.isUserSwap = true;
263→            game.dropGems();
