303→function areAdjacent(row1, col1, row2, col2) {
304→    const rowDiff = Math.abs(row1 - row2);
305→    const colDiff = Math.abs(col1 - col2);
306→    return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
307→}
