321→function canPreviewSwap(game, row1, col1, row2, col2) {
322→    if (areAdjacent(row1, col1, row2, col2)) {
323→        return true;
324→    }
325→
326→    if (game.activePowerUp === "swap" || game.activePowerUp === "teleport") {
327→        return true;
328→    }
329→
330→    if (isTeleportSwapAllowed(game, row1, col1, row2, col2)) {
331→        return true;
332→    }
333→
334→    return isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
335→}
