381→function previewSwap(game, row1, col1, row2, col2) {
382→    // Clear previous previews
383→    clearDragPreviews();
384→
385→    // Add preview to both gems
386→    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
387→    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
388→
389→    if (gem1 && gem2) {
390→        gem1.classList.add("preview");
391→        gem2.classList.add("preview");
392→
393→        // Get tiles that would merge if swap completes
394→        const matchTiles = getMatchTilesForSwap(game, row1, col1, row2, col2);
395→
396→        // Highlight merge tiles
397→        for (const tile of matchTiles) {
398→            const matchGem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
399→            matchGem?.classList.add("merge-preview");
400→        }
401→
402→        // Highlight blocked tiles that would be unblocked
403→        // matchTiles are in PRE-SWAP coords, convert to POST-SWAP for adjacency check
404→        const blockedToUnblock = getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2);
405→        for (const pos of blockedToUnblock) {
406→            const blockedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
407→            blockedGem?.classList.add("unblock-preview");
408→        }
409→    }
410→}
411→
412→function getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2) {
413→    const blockedSet = new Set();
414→    const result = [];
415→
416→    for (const tile of matchTiles) {
417→        // Convert pre-swap to post-swap coordinates
418→        let checkRow = tile.row;
419→        let checkCol = tile.col;
420→        if (tile.row === row1 && tile.col === col1) {
421→            checkRow = row2;
422→            checkCol = col2;
423→        } else if (tile.row === row2 && tile.col === col2) {
424→            checkRow = row1;
425→            checkCol = col1;
426→        }
427→
428→        const adjacentPositions = [
429→            { row: checkRow - 1, col: checkCol },
430→            { row: checkRow + 1, col: checkCol },
431→            { row: checkRow, col: checkCol - 1 },
432→            { row: checkRow, col: checkCol + 1 },
433→        ];
434→
435→        for (const pos of adjacentPositions) {
436→            if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
437→                const key = `${pos.row}_${pos.col}`;
438→                if (!blockedSet.has(key)) {
439→                    const adjacentTile = game.board[pos.row][pos.col];
440→                    if (
441→                        isBlocked(adjacentTile) ||
442→                        isBlockedWithLife(adjacentTile) ||
443→                        isBlockedMovable(adjacentTile) ||
444→                        isBlockedWithMergeCount(adjacentTile)
445→                    ) {
446→                        blockedSet.add(key);
447→                        result.push(pos);
448→                    }
449→                }
450→            }
451→        }
452→    }
453→
454→    return result;
455→}
