  8→    isBlockedWithMergeCount,
  9→    isBlocked,
 10→    isBlockedMovable,
 11→    isNormal,
 12→    createTile,
 13→    createCursedTile,
 14→    isCursed,
 15→    getDisplayValue,
 16→    getFontSize,
 17→} from "./tile-helpers.js";
 18→import { savePowerUpCounts, isFeatureUnlocked } from "./storage.js";
 19→import { track } from "./tracker.js";
 20→import {
 21→    isTutorialActive,
