 27→export function setupPowerUps(game) {
 28→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
 29→
 30→    powerUpButtons.forEach((button) => {
 31→        button.addEventListener("click", () => {
 32→            if (!game.gameActive) return;
 33→
 34→            const powerUpType = button.dataset.powerup;
 35→
 36→            if (!isPowerUpButtonVisible(game, powerUpType)) {
 37→                return;
 38→            }
 39→
 40→            if (getTotalPowerUpCount(game, powerUpType) <= 0) {
 41→                openPowerupShop(game);
 42→                return;
 43→            }
 44→
 45→            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 46→                if (!isValidTutorialPowerUp(game, powerUpType)) {
 47→                    return;
 48→                }
 49→            }
 50→
 51→            if (game.activePowerUp === powerUpType) {
 52→                deactivatePowerUp(game);
 53→            } else {
 54→                activatePowerUp(game, powerUpType);
 55→            }
 56→        });
 57→    });
 58→}
