 79→export function deactivatePowerUp(game) {
 80→    if (game.activePowerUp) {
 81→        const button = document.querySelector(`[data-powerup="${game.activePowerUp}"]`);
 82→        if (button) {
 83→            button.classList.remove("active");
 84→        }
 85→    }
 86→
 87→    game.activePowerUp = null;
 88→    game.powerUpSwapTiles = [];
