120→export function consumePowerUp(game, type) {
121→    game.powerUpUsedCounts[type]++;
122→
123→    const counts = game.powerUpCounts[type];
124→    if (counts.transient > 0) {
125→        counts.transient--;
126→    } else if (game.persistentPowerUpsEnabled && counts.persistent > 0) {
127→        counts.persistent--;
128→        savePowerUpCounts({
129→            hammer: game.powerUpCounts.hammer.persistent,
130→            halve: game.powerUpCounts.halve.persistent,
131→            swap: game.powerUpCounts.swap.persistent,
132→            teleport: game.powerUpCounts.teleport.persistent,
133→            wildcard: game.powerUpCounts.wildcard.persistent,
134→        });
135→    }
