290→export function handlePowerUpAction(game, row, col, element) {
291→    const tile = game.board[row][col];
292→
293→    switch (game.activePowerUp) {
294→        case "hammer":
295→            if (!tile) return;
296→            const allowedTypes = [
297→                TILE_TYPE.NORMAL,
298→                TILE_TYPE.BLOCKED_MOVABLE,
299→                TILE_TYPE.BLOCKED,
300→                TILE_TYPE.BLOCKED_WITH_LIFE,
301→            ];
302→            if (!allowedTypes.includes(tile.type)) return;
303→            usePowerUpHammer(game, row, col, element);
304→            break;
305→        case "halve":
306→            usePowerUpHalve(game, row, col, element);
307→            break;
308→        case "swap":
309→        case "teleport":
310→            return false;
311→        case "wildcard":
312→            usePowerUpWildcard(game, row, col, element);
313→            break;
314→    }
315→}
