398→                    game.renderBoard();
399→                    game.animating = false;
400→                    deactivatePowerUp(game);
401→                }, 200);
402→            }
403→        } else {
404→            game.animating = false;
405→            deactivatePowerUp(game);
406→        }
407→    } else if (isBlocked(tile) || isBlockedMovable(tile)) {
408→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
409→        element.style.opacity = "0";
410→        element.style.transform = "scale(0)";
411→
412→        setTimeout(() => {
413→            if (isRectangularBlocked(tile)) {
414→                for (let r = tile.rectAnchor.row; r < tile.rectAnchor.row + tile.rectHeight; r++) {
415→                    for (let c = tile.rectAnchor.col; c < tile.rectAnchor.col + tile.rectWidth; c++) {
416→                        if (r >= 0 && r < game.boardHeight && c >= 0 && c < game.boardWidth) {
417→                            game.board[r][c] = null;
418→                        }
419→                    }
420→                }
421→            } else {
422→                game.board[row][col] = null;
423→            }
424→
425→            game.updateBlockedTileGoals();
426→            game.dropGems();
427→            deactivatePowerUp(game);
428→        }, 300);
429→    } else {
430→        element.style.transition = "transform 0.3s ease, opacity 0.3s ease";
431→        element.style.opacity = "0";
432→        element.style.transform = "scale(0)";
