    isFeatureUnlocked,
    saveUnlockedFeature,
    loadHintsEnabled,
    loadHintTimeoutMs,
    loadAllowNonMatchingSwaps,
    loadExtendedFreeSwap,
    loadFormationPowerUpRewards,
    loadPersistentPowerUpsEnabled,
    loadSelectedPowerUps,
    loadSuperStrikeWildcardTeleport,
} from "./storage.js";
