        this.FORMATION_TYPES = FORMATION_TYPES;

        // Match statistics tracking
        this.matchStats = {
            match3Count: 0,
            match4Count: 0,
            match5Count: 0,
            tFormationCount: 0,
            lFormationCount: 0,
            blockFormationCount: 0,
        };

        // Power-up usage tracking (per level)
        this.powerUpUsedCounts = {
            hammer: 0,
            halve: 0,
            swap: 0,
            teleport: 0,
            wildcard: 0,
        };

        // Level timing
        this.levelStartTime = null;
        this.settingsChangedDuringLevel = false;

