// Main Match3Game class - orchestrates all game modules

import {
    TILE_TYPE,
    SPECIAL_TILE_TYPES,
    FORMATION_TYPES,
    DEFAULT_TILE_VALUES,
    SUPER_STREAK_THRESHOLD,
    DEFAULT_LEVEL,
    LEVEL_CONFIGS,
    FEATURE_KEYS,
} from "./config.js";
import {
    loadSpecialTileConfig,
    loadCurrentLevel,
    saveCurrentLevel,
