    color: #aee96b;
    margin: 0 0 10px 0;
    font-size: 1.3rem;
    font-weight: 700;
}

.intro-section h4 {
    margin: 15px 0 8px 0;
    font-size: 1rem;
    color: rgba(255, 255, 255, 0.9);
}

.intro-section p {
    margin: 0 0 10px 0;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.85);
}

.intro-section ul {
    margin: 10px 0;
    padding-left: 20px;
}

.intro-section li {
    margin: 5px 0;
    line-height: 1.4;
    color: rgba(255, 255, 255, 0.85);
}

