    background: rgba(255, 255, 255, 0.05);
    border-radius: 12px;
    padding: 15px;
    margin: 15px 0;
    /* border-left: 4px solid #aee96b; */
}

.formation-example h4 {
    margin: 0 0 10px 0;
    color: rgba(255, 255, 255, 0.9);
    font-size: 1rem;
}

.formation-example p {
    margin: 10px 0 0 0;
    font-size: 0.9rem;
    color: rgba(255, 255, 255, 0.7);
    font-weight: bold;
}

.example-grid {
    /* background-color: rgba(255,255,255,0.1); */
    border-radius: 6px;
    padding: 6px;
}

.example-tiles {
    display: flex;
    align-items: center;
    gap: 1px;
    flex-wrap: wrap;
}

.example-formations-row {
    display: flex;
    justify-content: space-around;
    align-items: center;
    gap: 10px;
    /* margin: 10px 0px; */
}

.example-result-row {
    display: flex;
    align-items: center;
}

.merge-indicator {
    display: flex;
    justify-content: center;
    padding: 8px 0;
}

