    width: 32px;
    height: 32px;
    background: rgba(174, 233, 107, 0.2);
    border: 2px solid rgba(174, 233, 107, 0.5);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    color: #aee96b;
    font-weight: bold;
