@import url("./styles/game.css");

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    zoom: 1;
    -moz-transform: scale(1);
    -moz-transform-origin: 0 0;
    transform: scale(1);
    transform-origin: 0 0;
}

:root {
    /* Tile colors */
    --tile-1-bg: #ffffff;
    --tile-1-color: black;
    --tile-2-bg: #ffe4ae;
    --tile-2-color: black;
    --tile-3-bg: #ffc655;
    --tile-3-color: black;
    --tile-4-bg: #ff9419;
    --tile-4-color: black;
    --tile-5-bg: #ff5c3c;
    --tile-5-color: black;
    --tile-6-bg: #ff3033;
    --tile-6-color: white;
    --tile-7-bg: #95d3ff;
    --tile-7-color: black;
    --tile-8-bg: #3c9dff;
    --tile-8-color: white;
    --tile-9-bg: #005eff;
    --tile-9-color: white;
    --tile-10-bg: #bb00ff;
    --tile-10-color: white;
    --tile-11-bg: #ff00bf;
    --tile-11-color: white;

    /* Special tile colors */
    --tile-joker-bg: linear-gradient(135deg, #9c27b0 0%, #e91e63 100%);
    --tile-joker-color: white;
    --tile-joker-border: #fff6;

    --tile-cursed-bg: linear-gradient(135deg, #6a1b9a 0%, #4a148c 100%);
    --tile-cursed-border: #9c27b0;
    --tile-cursed-color: white;
    --tile-cursed-badge-bg: #9c27b0;

    --tile-freeswap-border: #00bcd4;
    --tile-freeswap-badge-bg: #00bcd4;
    --tile-freeswap-badge-color: white;

    --tile-hammer-border: #ff5722;
    --tile-hammer-badge-bg: #ff5722;
    --tile-hammer-badge-color: white;

    --tile-halver-border: #9c27b0;
    --tile-halver-badge-bg: #9c27b0;
    --tile-halver-badge-color: white;

    --tile-teleport-border: #00bcd4;
    --tile-teleport-badge-bg: #00bcd4;
    --tile-teleport-badge-color: white;

    --tile-wild-teleport-border: #e040fb;
    --tile-wild-teleport-badge-bg: #e040fb;

    --tile-plus-border: #9c27b0;
    --tile-plus-badge-bg: linear-gradient(135deg, #9c27b0 0%, #e91e63 100%);
    --tile-plus-badge-color: white;

    --tile-blocked-bg: #3c3c3c;
    --tile-blocked-border: #666;
    --tile-blocked-x-color: #666;
    --tile-blocked-life-color: #fff;

    --tile-blocked-movable-bg: #3c3c3c;
    --tile-blocked-movable-border: #666;
    --tile-blocked-movable-icon-color: white;
}

body {
    font-family: Arial, sans-serif;
    background: #222 url("assets/bg.png");
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    min-height: 100vh;
    min-height: 100dvh; /* Dynamic viewport height for mobile browsers */
    display: flex;
    justify-content: center;
    align-items: center;
    touch-action: none;
    user-select: none;
    box-sizing: border-box;

    -webkit-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
    user-select: none;
}

/* Safari-specific viewport fixes */
@supports (-webkit-touch-callout: none) {
    body {
        min-height: -webkit-fill-available;
        padding-top: env(safe-area-inset-top, 10px);
    }
}

button {
    -webkit-tap-highlight-color: transparent;
}

/* Introduction Dialog Styles */
.intro-dialog-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
    backdrop-filter: blur(8px);
    opacity: 1;
    transition: opacity 0.3s ease;
}

.intro-dialog {
    padding: 20px;
    background: #141414;
    border-radius: 24px;
    max-width: 500px;
    border: 3px solid black;
    width: 85%;
    max-height: 85vh;
    box-shadow: 0 24px 48px rgba(0, 0, 0, 0.4);
    animation: slideIn 0.3s ease-out;
    display: flex;
    flex-direction: column;
    font-family: "Nunito", sans-serif;
    color: white;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: scale(0.9) translateY(-20px);
    }
    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

@keyframes unblock-move {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(0.8);
        opacity: 0.7;
    }
    100% {
        transform: scale(0.3);
        opacity: 0;
    }
}

@keyframes popShrink {
    0% {
        transform: scale(1);
    }
    20% {
        transform: scale(1.1); /* kurz größer */
    }
    100% {
        transform: scale(0);
    }
}

.disappear {
    animation: popShrink 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
}

.intro-header {
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    color: white;
    border-radius: 24px 24px 0 0;
    text-align: center;
    position: relative;
}

.intro-header h2 {
    font-size: 2.5rem;
    font-weight: 900;
}

.intro-content {
    padding: 20px 0px;
    margin-bottom: 12px;
    overflow-y: auto;
    color: white;
    flex: 1;
    font-family: "Nunito", sans-serif;
}

.intro-section {
    margin-bottom: 20px;
    /* padding: 0 20px; */
}

.intro-section h3 {
    color: #aee96b;
    margin: 0 0 10px 0;
    font-size: 1.3rem;
    font-weight: 700;
}

.intro-section h4 {
    margin: 15px 0 8px 0;
    font-size: 1rem;
    color: rgba(255, 255, 255, 0.9);
}

.intro-section p {
    margin: 0 0 10px 0;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.85);
}

.intro-section ul {
    margin: 10px 0;
    padding-left: 20px;
}

.intro-section li {
    margin: 5px 0;
    line-height: 1.4;
    color: rgba(255, 255, 255, 0.85);
}

.formation-example {
