    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100dvh;
    pointer-events: none;
    z-index: 1000;
    display: flex;
    /* align-items: center; */
    justify-content: center;
}

.tutorial-overlay.hidden {
    display: none;
}

.tutorial-hint-box {
    position: absolute;
    bottom: 6vh; /* is overwritten in tutorial.js */
    background: rgba(20, 20, 20, 1);
    border: 3px solid #000;
    border-radius: 16px;
    padding: 8px 16px;
    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
    animation: tutorialHintPulse 2s ease-in-out infinite;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    max-width: 80%;

    &::before {
        content: "💡";
        font-size: clamp(28px, 8vw, 40px);
    }
}

.tutorial-hint-text {
    color: #fff;
    font-family: Nunito, Arial, sans-serif;
    font-size: clamp(16px, 4vw, 20px);
    font-weight: 700;
    text-align: center;
    margin: 0;
}

.tutorial-hand {
    position: absolute;
    width: 60px;
    height: 60px;
    pointer-events: none;
    filter: drop-shadow(0 4px 8px rgba(0, 0, 0, 0.5));
    z-index: 1001;
}

.tutorial-hand.hidden {
    display: none;
}

.tutorial-hand.animating-swipe {
    animation: tutorialHandSwipe 2s ease-in-out infinite;
}

.tutorial-hand.animating-tap {
    animation: tutorialHandTap 1.5s ease-in-out infinite;
}

@keyframes tutorialHandSwipe {
    0% {
        transform: translate(0, 0);
        scale: 1.4;
        opacity: 1;
    }
    25% {
        transform: translate(0, 0);
        opacity: 1;
        scale: 1;
    }
    75%,
    100% {
        transform: translate(calc(var(--hand-dx)), calc(var(--hand-dy)));
        opacity: 1;
    }
}

@keyframes tutorialHandTap {
    0%,
    100% {
        transform: translate(30%, 30%) scale(1);
        opacity: 0.85;
    }
    50% {
        transform: translate(30%, 30%) scale(0.85);
        opacity: 1;
    }
}

@keyframes tutorialHintPulse {
    0%,
    100% {
        transform: scale(1);
    }
    50% {
        transform: scale(1.02);
    }
}

