.gem.tile-BLOCKED {
    background: var(--tile-blocked-bg);
    color: transparent;
    border: 2px solid var(--tile-blocked-border);
    position: relative;
    overflow: hidden;
}

.gem.tile-BLOCKED::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_WITH_LIFE {
    background: var(--tile-blocked-bg);
    color: var(--tile-blocked-life-color);
    border: 2px solid var(--tile-blocked-border);
    font-size: clamp(1.2rem, 4vw, 1.8rem);
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: visible;
}

.gem.tile-BLOCKED_WITH_LIFE::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
    z-index: 0;
}

.gem.tile-BLOCKED_WITH_LIFE::after {
    content: attr(data-life);
    position: relative;
    z-index: 1;
    color: var(--tile-blocked-life-color);
    font-size: clamp(1rem, 40cqw, 1.2rem);
    font-weight: bold;
}

/* Blocked tile damage shake */
@keyframes blockedShake {
    0%,
    100% {
        transform: translateX(0);
    }
    15% {
        transform: translateX(calc(-1 * var(--shake-intensity)));
    }
    30% {
        transform: translateX(var(--shake-intensity));
    }
    45% {
        transform: translateX(calc(-0.7 * var(--shake-intensity)));
    }
    60% {
        transform: translateX(calc(0.5 * var(--shake-intensity)));
    }
    75% {
        transform: translateX(calc(-0.3 * var(--shake-intensity)));
    }
}

.gem.blocked-damaged {
    animation: blockedShake 0.35s ease-out;
}

/* Floating damage text */
@keyframes damageFloat {
    0% {
        opacity: 1;
        transform: translateX(-10%) translateY(0) scale(1);
    }
    20% {
        opacity: 1;
        transform: translateX(-10%) translateY(-10px) scale(1.1);
    }
    100% {
        opacity: 0;
        transform: translateX(-10%) translateY(-50px) scale(0.8);
    }
}

.damage-text {
    position: fixed;
    z-index: 1000;
    pointer-events: none;
    font-weight: bolder;
    font-style: italic;
    font-size: clamp(0.6rem, 30cqw, 1.2rem);
    color: #ff4444;
    text-shadow:
        0 0 3px rgba(0, 0, 0, 0.8),
        0 1px 2px rgba(0, 0, 0, 0.6);
    animation: damageFloat 0.8s ease-out forwards;
}

.gem.tile-BLOCKED_WITH_LIFE.unblocking {
    animation: shakeShrink 0.6s ease-out forwards;
    z-index: 200;
}

@keyframes shakeShrink {
    0% {
        transform: translateX(0) scale(1);
        opacity: 1;
    }
    10% {
        transform: translateX(calc(-1 * var(--shake-intensity, 8px))) scale(1.05);
    }
    20% {
        transform: translateX(calc(var(--shake-intensity, 8px))) scale(1.05);
    }
    25% {
        transform: translateX(calc(-0.7 * var(--shake-intensity, 8px))) scale(1.05);
    }
    30% {
        transform: translateX(calc(0.5 * var(--shake-intensity, 8px))) scale(1.05);
    }
    35% {
        transform: translateX(calc(-0.3 * var(--shake-intensity, 8px))) scale(1.05);
    }
    40% {
        transform: translateX(0) scale(0.95);
    }
    45% {
        transform: translateX(0) scale(0.9);
    }
    55% {
        transform: translateX(0) scale(0.7);
        opacity: 0.8;
    }
    100% {
        transform: translateX(0) scale(0);
        opacity: 0;
    }
}

.gem.shake-shrink {
    animation: shakeShrink 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_MOVABLE {
