    color: transparent;
    border: 2px solid var(--tile-blocked-movable-border);
    position: relative;
    overflow: visible;
    cursor: pointer;
}

.gem.tile-BLOCKED_MOVABLE::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED_MOVABLE::after {
    content: "";
    width: 60%;
    height: 60%;
    position: absolute;
    top: 44%;
    left: 50%;
    transform: translate(-50%, -50%);
